// Get data directly from the Error Trigger node
const errorData = $input.first().json;

const workflowName = errorData.workflow?.name || 'Unknown Workflow';
const workflowId   = errorData.workflow?.id   || 'N/A';
const executionId  = errorData.execution?.id  || 'N/A';
const errorMessage = errorData.error?.message || 'No error message provided';
const errorNode    = errorData.node?.name     || 'Unknown Node';
const startedAt    = errorData.execution?.lastUpdatedAt || new Date().toISOString();
const mode         = errorData.execution?.mode || 'unknown';

// IMPORTANT: Set your real n8n instance URL here
const n8nHost      = 'https://n8n-997501160612.us-central1.run.app'; 
const executionUrl = `${n8nHost}/execution/${executionId}`;

const subject = `🚨 n8n Error: ${workflowName}`;

const html = `
<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <style>
    body { font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif; background: #f4f4f4; padding: 20px; }
    .container { background: #ffffff; border-radius: 8px; padding: 30px; max-width: 600px; margin: auto; border-left: 5px solid #e53e3e; box-shadow: 0 4px 6px rgba(0,0,0,0.1); }
    h2 { color: #e53e3e; margin-top: 0; font-size: 22px; }
    .badge { display: inline-block; background: #e53e3e; color: white; padding: 4px 12px; border-radius: 20px; font-size: 12px; font-weight: bold; margin-bottom: 20px; text-transform: uppercase; }
    table { width: 100%; border-collapse: collapse; margin-top: 16px; }
    td { padding: 12px 12px; border-bottom: 1px solid #eee; font-size: 14px; color: #333; }
    td:first-child { font-weight: bold; color: #666; width: 150px; }
    .error-box { background: #fff5f5; border: 1px solid #feb2b2; border-radius: 6px; padding: 16px; margin-top: 20px; font-family: 'Courier New', Courier, monospace; font-size: 13px; color: #c53030; word-break: break-all; }
    .btn { display: inline-block; margin-top: 24px; background: #e53e3e; color: #ffffff !important; padding: 12px 24px; border-radius: 6px; text-decoration: none; font-weight: bold; font-size: 14px; text-align: center; }
    .footer { margin-top: 30px; font-size: 11px; color: #999; text-align: center; line-height: 1.5; }
  </style>
</head>
<body>
  <div class="container">
    <h2>🚨 Workflow Error Detected</h2>
    <span class="badge">Automation Alert</span>
    <table>
      <tr><td>Workflow Name</td><td>${workflowName}</td></tr>
      <tr><td>Workflow ID</td><td>${workflowId}</td></tr>
      <tr><td>Execution ID</td><td>${executionId}</td></tr>
      <tr><td>Failed Node</td><td>${errorNode}</td></tr>
      <tr><td>Execution Mode</td><td>${mode}</td></tr>
      <tr><td>Timestamp</td><td>${startedAt}</td></tr>
    </table>
    <div class="error-box">
      <strong>Error Message:</strong><br/>${errorMessage}
    </div>
    <div style="text-align: center;">
      <a href="${executionUrl}" class="btn">🔍 View Execution in n8n</a>
    </div>
    <div class="footer">
      This is an automated message sent by your <strong>Global Error Handler</strong>.<br/>
      Please check the execution logs to resolve the issue.
    </div>
  </div>
</body>
</html>
`;

return [{
  json: {
    subject,
    html,
    workflowName,
    executionId,
    errorMessage,
    errorNode
  }
}];
